// Données produits
const produits = [
  { id: '1', nom: 'Sac à dos', prix: 15000, description: 'Sac imperméable 20L', image: 'https://...' },
  { id: '2', nom: 'T-shirt', prix: 5000, description: 'Coton bio', image: 'https://...' },
];

function ListeProduits({ navigation }) {
  const handlePress = (produit) => {
    // Passage de l'objet complet (simple pour peu de données)
    navigation.navigate('Detail', { produit });
  };

  return (
    <FlatList
      data={produits}
      keyExtractor={(item) => item.id}
      renderItem={({ item }) => (
        <TouchableOpacity onPress={() => handlePress(item)} style={styles.item}>
          <Text style={styles.nom}>{item.nom}</Text>
          <Text style={styles.prix}>{item.prix} FCFA</Text>
        </TouchableOpacity>
      )}
    />
  );
}

function DetailProduit({ route }) {
  const { produit } = route.params;
  return (
    <View style={styles.container}>
      <Text style={styles.nom}>{produit.nom}</Text>
      <Text style={styles.prix}>{produit.prix} FCFA</Text>
      <Text>{produit.description}</Text>
    </View>
  );
}
```

**Choix expliqué :** Dans cet exemple simple, passer l'objet complet est acceptable car les données sont petites. <strong>Pour des applications réelles</strong>, il est préférable de passer uniquement l'ID, puis de re-fetch les données dans l'écran de détail (via API ou state global). Cela évite les problèmes de synchronisation et réduit la taille des paramètres.

