import { Alert, BackHandler } from 'react-native';
import { useFocusEffect } from '@react-navigation/native';

function QuestionScreen({ navigation, route }) {
  const { questionId, totalQuestions } = route.params;

  // Gestion du bouton retour Android
  useFocusEffect(
    React.useCallback(() => {
      const onBackPress = () => {
        Alert.alert(
          'Quitter le quiz',
          'Voulez-vous vraiment quitter ? Votre progression sera perdue.',
          [
            { text: 'Annuler', style: 'cancel' },
            { text: 'Quitter', onPress: () => navigation.popToTop() } // retour à l'accueil
          ]
        );
        return true; // empêche l'action par défaut
      };
      BackHandler.addEventListener('hardwareBackPress', onBackPress);
      return () => BackHandler.removeEventListener('hardwareBackPress', onBackPress);
    }, [navigation])
  );

  // Désactiver le bouton retour du header personnalisé
  React.useLayoutEffect(() => {
    navigation.setOptions({
      headerLeft: () => (
        <Button
          title="Retour"
          onPress={() => {
            Alert.alert('Quitter', 'Voulez-vous vraiment quitter ?', [
              { text: 'Annuler', style: 'cancel' },
              { text: 'Quitter', onPress: () => navigation.popToTop() }
            ]);
          }}
        />
      ),
    });
  }, [navigation]);

  const handleNext = () => {
    if (questionId < totalQuestions) {
      navigation.push('Question', { questionId: questionId + 1, totalQuestions });
    } else {
      navigation.navigate('Resultats', { score: 85 });
    }
  };

  return (
    <View>
      <Text>Question {questionId}/{totalQuestions}</Text>
      <Button title="Réponse suivante" onPress={handleNext} />
    </View>
  );
}
```
Ce code gère à la fois le bouton retour physique Android (avec `BackHandler`) et le bouton retour du header (en utilisant `setOptions`).
